diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..b2a008a9a914 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2225,17 +2225,60 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   Value *Op0 = I.getOperand(0);
   Value *Op1 = I.getOperand(1);
   Type *Ty = I.getType();
-  auto *MinMax = dyn_cast<MinMaxIntrinsic>(Op1);
-  if (!MinMax)
+  auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0);
+  auto *MinMax1 = dyn_cast<MinMaxIntrinsic>(Op1);
+  if (!MinMax1) {
+    // If Op1 is not a min/max but Op0 is, try swapping: the pattern
+    // sub(min(...), X) may match after commuting; but foldSubOfMinMax
+    // currently only handles min/max as the subtrahend.
+    if (!MinMax0)
+      return nullptr;
+    // Swap Op0 and Op1 to handle min as Op0: sub(min(X, Y), Z) is not
+    // the pattern we look for here; fall through only if both are min/max.
     return nullptr;
+  }
+  if (MinMax0 && MinMax0->getIntrinsicID() == MinMax1->getIntrinsicID() &&
+      (MinMax0->hasOneUse() || MinMax1->hasOneUse())) {
+    // sub(smin(X+1, Y), smin(X, Y)) -> (X < Y) ? 1 : 0
+    // sub(smax(X+1, Y), smax(X, Y)) -> (X > Y) ? 1 : 0
+    // sub(umin(X+1, Y), umin(X, Y)) -> (X < Y) ? 1 : 0
+    // sub(umax(X+1, Y), umax(X, Y)) -> (X > Y) ? 1 : 0
+    Value *A0 = MinMax0->getLHS(), *B0 = MinMax0->getRHS();
+    Value *A1 = MinMax1->getLHS(), *B1 = MinMax1->getRHS();
+    Value *X, *Y;
+    bool IsSigned = MinMax0->isSigned();
+    // Match add nsw/nuw X, 1 or or disjoint X, 1
+    auto MatchAddLike = [&](Value *V) -> bool {
+      if (match(V, m_Add(m_Value(X), m_One()))) {
+        auto *OBO = cast<OverflowingBinaryOperator>(V);
+        return IsSigned ? OBO->hasNoSignedWrap() : OBO->hasNoUnsignedWrap();
+      }
+      if (match(V, m_DisjointOr(m_Value(X), m_One())))
+        return true;
+      return false;
+    };
+    // Check all four operand orderings
+    if ((MatchAddLike(A0) && B0 == B1 && A1 == X) ||
+        (MatchAddLike(B0) && A0 == A1 && B1 == X) ||
+        (MatchAddLike(A0) && B0 == A1 && B1 == X) ||
+        (MatchAddLike(B0) && A0 == B1 && A1 == X)) {
+      // Found: min(X+1, Y) - min(X, Y)
+      Y = (A0 == A1 ? A0 : (B0 == B1 ? B0 : (B0 == A1 ? B0 : A0)));
+      ICmpInst::Predicate Pred = MinMaxIntrinsic::getPredicate(
+          MinMax0->getIntrinsicID());
+      Value *Cmp = Builder.CreateICmp(Pred, X, Y);
+      return CastInst::CreateZExtOrBitCast(Cmp, Ty);
+    }
+  }

+  // sub(add(X,Y), s/umin(X,Y)) --> s/umax(X,Y)
   // sub(add(X,Y), s/umin(X,Y)) --> s/umax(X,Y)
   // sub(add(X,Y), s/umax(X,Y)) --> s/umin(X,Y)
-  Value *X = MinMax->getLHS();
-  Value *Y = MinMax->getRHS();
+  Value *X = MinMax1->getLHS();
+  Value *Y = MinMax1->getRHS();
   if (match(Op0, m_c_Add(m_Specific(X), m_Specific(Y))) &&
       (Op0->hasOneUse() || Op1->hasOneUse())) {
-    Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax->getIntrinsicID());
+    Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax1->getIntrinsicID());
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {X, Y});
   }
@@ -2256,9 +2299,9 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,

   // sub Op0, smin((sub nsw Op0, Z), 0) --> smax Op0, Z
   // sub Op0, smax((sub nsw Op0, Z), 0) --> smin Op0, Z
-  if (MinMax->isSigned() && match(Y, m_ZeroInt()) &&
+  if (MinMax1->isSigned() && match(Y, m_ZeroInt()) &&
       match(X, m_NSWSub(m_Specific(Op0), m_Value(Z)))) {
-    Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax->getIntrinsicID());
+    Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax1->getIntrinsicID());
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {Op0, Z});
   }

